-- Migration 048 : colonnes ton + longueur + remplacement complet des modèles système

ALTER TABLE message_templates
  ADD COLUMN IF NOT EXISTS ton     TEXT CHECK (ton     IN ('tu','vous')),
  ADD COLUMN IF NOT EXISTS longueur TEXT CHECK (longueur IN ('court','moyen','long'));

-- Suppression des anciens modèles système
DELETE FROM message_templates WHERE is_system = true;

